8→  const [password, setPassword] = useState('');
9→  const [error, setError] = useState('');
10→  const [loading, setLoading] = useState(false);
11→  const [rememberMe, setRememberMe] = useState(false);
12→
13→  useEffect(() => {
14→    const savedUsername = localStorage.getItem('sr_username');
15→    if (savedUsername) {
16→      setUsername(savedUsername);
17→      setRememberMe(true);
18→    }
19→  }, []);
20→
21→  const handleSubmit = async (e) => {
22→    e.preventDefault();
23→    setLoading(true);
24→    setError('');
25→    try {
26→      const response = await axios.post(`${API}/token`,
27→        new URLSearchParams({ username, password }),
28→        { headers: { 'Content-Type': 'application/x-www-form-urlencoded' } }
29→      );
30→      const token = response.data.access_token;
31→      localStorage.setItem('sr_token', token);
32→      
33→      if (rememberMe) {
34→        localStorage.setItem('sr_username', username);
35→      } else {
36→        localStorage.removeItem('sr_username');
37→      }
38→      
39→      const userResponse = await axios.get(`${API}/users/me`, {
40→        headers: { Authorization: `Bearer ${token}` }
41→      });
42→      onLogin(userResponse.data);
43→    } catch (err) {
44→      setError('Login yoki parol xato');
45→      setLoading(false);
46→    }
47→  };
48→
49→  return (
