55→          </div>
56→          <h2 className="login-title">SMART ESP32</h2>
57→          <p className="login-subtitle">Industrial Monitoring Portal</p>
58→        </div>
59→
60→        {error && <div className="login-error">{error}</div>}
61→
62→        <div className="login-field">
63→          <label>Foydalanuvchi</label>
64→          <input 
