66→            placeholder="Login kiriting"
67→            value={username} 
68→            onChange={(e) => setUsername(e.target.value)} 
69→            required 
70→            autoFocus
71→          />
72→        </div>
73→
74→        <div className="login-field">
75→          <label>Parol</label>
76→          <input 
77→            type="password" 
78→            placeholder="Parol kiriting"
79→            value={password} 
80→            onChange={(e) => setPassword(e.target.value)} 
81→            required 
82→          />
83→        </div>
84→
85→        <div className="login-remember">
86→          <label>
87→            <input 
88→              type="checkbox" 
89→              checked={rememberMe} 
90→              onChange={(e) => setRememberMe(e.target.checked)} 
91→            />
92→            <span>Eslab qol</span>
93→          </label>
94→        </div>
95→
96→        <button type="submit" className="btn-submit login-btn" disabled={loading}>
97→          {loading ? 'Kutilmoqda...' : 'Kirish'}
